import { computed } from 'vue';

export const useTheme = () => {
  // Always true as per request to remove bright theme
  const isDark = computed(() => true);

  const toggleTheme = () => {
    // Theme switching is disabled
  };

  const initTheme = () => {
    // No initialization needed
  };

  return {
    isDark,
    toggleTheme,
    initTheme
  };
};
import { ref } from 'vue';
import { useRoute, useAuth, useTheme } from '#imports';

export default {
  setup() {
    const route = useRoute();
    const { user, logout } = useAuth();
    const { isDark } = useTheme();

    const isMenuOpen = ref(false);

    const handleLogout = async () => {
      isMenuOpen.value = false;
      await logout();
    };

    return {
      route,
      user,
      isDark,
      isMenuOpen,
      handleLogout
    };
  }
};
<template>
  <header class="header nav-glass">
    <div class="logo-container">
      <NuxtLink :to="user ? '/dashboard' : '/'" class="logo logo-gradient">RiskAnalyzer</NuxtLink>

      <div class="search-container">
        <span class="material-symbols-outlined search-icon">search</span>
        <input class="search-input" placeholder="Search insights..." type="text"/>
      </div>

      <nav class="nav-links">
        <NuxtLink
          to="/dashboard"
          class="nav-link"
          :class="{ active: route.path === '/dashboard' }"
        >
          <span class="material-symbols-outlined" :style="route.path === '/dashboard' ? 'font-variation-settings: \'FILL\' 1;' : ''">dashboard</span>
          <span>Overview</span>
        </NuxtLink>
        <NuxtLink
          to="/analyze"
          class="nav-link"
          :class="{ active: route.path === '/analyze' }"
        >
          <span class="material-symbols-outlined" :style="route.path === '/analyze' ? 'font-variation-settings: \'FILL\' 1;' : ''">security</span>
          <span>Threat Actors</span>
        </NuxtLink>
      </nav>
    </div>

    <div class="actions-container">
      <div class="desktop-actions">
        <ClientOnly>
          <button v-if="user" @click="handleLogout" class="logout-btn" title="Logout">
            <span class="material-symbols-outlined">logout</span>
          </button>
          <NuxtLink v-else to="/" class="signin-btn">SIGN IN</NuxtLink>
        </ClientOnly>
      </div>

      <button @click="isMenuOpen = true" class="hamburger-btn">
        <span class="material-symbols-outlined">menu</span>
      </button>
    </div>

    <!-- Mobile Drawer -->
    <Transition name="drawer">
      <div v-if="isMenuOpen" class="mobile-drawer">
        <div @click="isMenuOpen = false" class="drawer-overlay"></div>

        <div class="drawer-content">
          <div class="drawer-header">
            <span class="logo-gradient" style="font-size: 1.25rem; font-weight: 700;">RiskAnalyzer</span>
            <button @click="isMenuOpen = false" class="close-btn">
              <span class="material-symbols-outlined">close</span>
            </button>
          </div>

          <nav class="mobile-nav">
            <NuxtLink
              to="/dashboard"
              @click="isMenuOpen = false"
              class="mobile-link"
              :class="{ active: route.path === '/dashboard' }"
            >
              <span class="material-symbols-outlined">dashboard</span>
              <span>Overview</span>
            </NuxtLink>

            <NuxtLink
              to="/analyze"
              @click="isMenuOpen = false"
              class="mobile-link"
              :class="{ active: route.path === '/analyze' }"
            >
              <span class="material-symbols-outlined">security</span>
              <span>Threat Actors</span>
            </NuxtLink>

            <div style="height: 1px; background: rgba(255,255,255,0.1); margin: 0.5rem 0;"></div>

            <button style="display: flex; align-items: center; gap: 1rem; padding: 1rem; border-radius: 0.75rem; color: #64748b; background: none; border: none; cursor: not-allowed; opacity: 0.5; width: 100%; text-align: left;">
              <span class="material-symbols-outlined">settings</span>
              <span>Admin / Settings</span>
            </button>
          </nav>

          <div style="margin-top: auto; border-top: 1px solid rgba(255,255,255,0.1); padding-top: 1.5rem;">
            <button v-if="user" @click="handleLogout" style="width: 100%; padding: 0.75rem; border-radius: 0.75rem; background: rgba(239,68,68,0.1); color: #ef4444; border: 1px solid rgba(239,68,68,0.2); font-weight: 700; letter-spacing: 0.1em; font-size: 0.75rem; cursor: pointer;">
              LOG OUT
            </button>
            <NuxtLink v-else to="/" @click="isMenuOpen = false" style="display: block; width: 100%; padding: 1rem; text-align: center; border-radius: 0.75rem; background: var(--color-surface-tint); color: var(--color-on-primary); font-weight: 700; letter-spacing: 0.1em; font-size: 0.75rem; text-decoration: none;">
              SIGN IN
            </NuxtLink>
          </div>
        </div>
      </div>
    </Transition>
  </header>
</template>

<script src="../logic/StitchTopNav.js"></script>
<style src="./StitchTopNav.css" scoped></style>
import { useRoute } from '#imports';

export default {
  setup() {
    const route = useRoute();
    return { route };
  }
};
<template>
  <nav class="bottom-nav">
    <NuxtLink
      to="/dashboard"
      class="bottom-nav-link"
      :class="{ active: route.path === '/dashboard' }"
    >
      <span class="material-symbols-outlined bottom-nav-icon" :style="route.path === '/dashboard' ? 'font-variation-settings: \'FILL\' 1;' : ''">dashboard</span>
      <span class="bottom-nav-text">Overview</span>
    </NuxtLink>

    <NuxtLink
      to="/analyze"
      class="bottom-nav-link"
      :class="{ active: route.path === '/analyze' }"
    >
      <span class="material-symbols-outlined bottom-nav-icon" :style="route.path === '/analyze' ? 'font-variation-settings: \'FILL\' 1;' : ''">security</span>
      <span class="bottom-nav-text">Analyze</span>
    </NuxtLink>
  </nav>
</template>

<script src="../logic/StitchBottomNav.js"></script>
<style src="./StitchBottomNav.css" scoped></style>
import { computed, onMounted } from 'vue';
import { useRoute, useAuth, useTheme } from '#imports';

export default {
  setup() {
    const route = useRoute();
    const { checkAuth, hydrateFromStorage } = useAuth();
    const { initTheme } = useTheme();

    const isLanding = computed(() => route.path === '/');

    onMounted(() => {
      initTheme();
      hydrateFromStorage();
      checkAuth();
    });

    return {
      route,
      isLanding
    };
  }
};
<template>
  <div class="app-container">
    <!-- Resilient 3D Background -->
    <ClientOnly>
      <AnimatedBackground />
      <template #fallback>
        <div class="bg-loading-placeholder"></div>
      </template>
    </ClientOnly>

    <!-- Layout Content -->
    <div class="main-content">
      <StitchTopNav v-if="!isLanding" />

      <main 
        class="page-main"
        :class="{ 'with-nav': !isLanding }"
      >
        <slot />
      </main>

      <StitchBottomNav v-if="!isLanding" />
    </div>
  </div>
</template>

<script src="../logic/layout.js"></script>

<style>
.app-container {
  background-color: var(--color-background, #0c1324);
  color: var(--color-on-background, #dce1fb);
  min-height: 100vh;
  display: flex;
  font-family: 'Inter', sans-serif;
  overflow: hidden;
}

.bg-loading-placeholder {
  position: fixed;
  inset: 0;
  background: #081425;
  z-index: -1;
}

.main-content {
  flex: 1;
  display: flex;
  flex-direction: column;
  position: relative;
  z-index: 10;
  min-width: 0;
  width: 100%;
}

.page-main {
  flex: 1;
  overflow-y: auto;
  overflow-x: hidden;
  min-width: 0;
  width: 100%;
}

.page-main.with-nav {
  margin-top: 80px;
  padding: 1.5rem;
  height: calc(100vh - 80px);
  padding-bottom: 80px;
}

@media (max-width: 768px) {
  .page-main.with-nav {
    padding: 1rem;
    padding-bottom: 90px;
  }
}
</style>
